mapper.select:
SELECT b.id, b.bill_no AS billNo, b.fee_type AS feeType, b.amount, b.reduce_amount AS reduceAmount, b.paid_amount AS paidAmount, b.status, b.owner_id AS ownerId, b.owner_name AS ownerName, b.house_id AS houseId, b.billing_period AS billingPeriod, b.due_date AS dueDate, b.paid_time AS paidTime, b.batch_no AS batchNo, b.create_time AS createTime FROM bl_bill b WHERE b.del_flag = 0
AND b.status = #{query.status}
AND b.fee_type = #{query.feeType}
AND b.community_id = #{query.communityId}
AND b.building_id = #{query.buildingId}
AND b.billing_period = #{query.billingPeriod}
AND (b.bill_no LIKE CONCAT('%', #{query.keyword}, '%') OR b.owner_name LIKE CONCAT('%', #{query.keyword}, '%'))
ORDER BY b.create_time DESC

SELECT COALESCE(SUM(b.amount), 0)
FROM bl_bill b
WHERE b.del_flag = 0
  AND b.status NOT IN ('CANCELLED', 'REFUNDED')

    AND b.community_id = #{query.communityId}


    AND b.building_id = #{query.buildingId}


    AND b.fee_type = #{query.feeType}


    AND b.billing_period >= #{query.startDate}


    AND b.billing_period <= #{query.endDate}

SELECT COALESCE(SUM(b.paid_amount), 0)
FROM bl_bill b
WHERE b.del_flag = 0
  AND b.status IN ('PAID', 'REDUCED')

    AND b.community_id = #{query.communityId}


    AND b.building_id = #{query.buildingId}


    AND b.fee_type = #{query.feeType}


    AND b.billing_period >= #{query.startDate}


    AND b.billing_period <= #{query.endDate}

SELECT COALESCE(SUM(b.amount - COALESCE(b.reduce_amount, 0)), 0)
FROM bl_bill b
WHERE b.del_flag = 0
  AND b.status = 'OVERDUE'

    AND b.community_id = #{query.communityId}


    AND b.building_id = #{query.buildingId}


    AND b.fee_type = #{query.feeType}

SELECT COUNT(DISTINCT b.owner_id)
FROM bl_bill b
WHERE b.del_flag = 0
  AND b.status = 'OVERDUE'

    AND b.community_id = #{query.communityId}


    AND b.building_id = #{query.buildingId}


    AND b.fee_type = #{query.feeType}

SELECT COALESCE(SUM(b.reduce_amount), 0)
FROM bl_bill b
WHERE b.del_flag = 0
  AND b.reduce_amount > 0

    AND b.community_id = #{query.communityId}


    AND b.building_id = #{query.buildingId}


    AND b.fee_type = #{query.feeType}


    AND b.billing_period >= #{query.startDate}


    AND b.billing_period <= #{query.endDate}

SELECT b.billing_period AS period, COALESCE(SUM(b.amount), 0) AS receivable, COALESCE(SUM(CASE WHEN b.status IN ('PAID','REDUCED') THEN b.paid_amount ELSE 0 END), 0) AS received, CASE WHEN COALESCE(SUM(b.amount), 0) = 0 THEN 0 ELSE ROUND( COALESCE(SUM(CASE WHEN b.status IN ('PAID','REDUCED') THEN b.paid_amount ELSE 0 END), 0) / COALESCE(SUM(b.amount), 1) * 100, 2) END AS collectionRate FROM bl_bill b WHERE b.del_flag = 0 AND b.status NOT IN ('CANCELLED')
AND b.community_id = #{query.communityId}
AND b.fee_type = #{query.feeType}
AND b.billing_period >= #{query.startDate}
AND b.billing_period <= #{query.endDate}
GROUP BY b.billing_period ORDER BY b.billing_period ASC
